// WebClientConfig.java - Con autenticación automática
@Configuration
public class WebClientConfig {

    @Value("${service.product.username:admin}")
    private String productServiceUsername;

    @Value("${service.product.password:admin123}")
    private String productServicePassword;

    @Bean
    @LoadBalanced
    public WebClient.Builder webClientBuilder() {
        return WebClient.builder();
    }

    @Bean
    public WebClient productWebClient(WebClient.Builder builder) {
        // Opción 1: Header estático con credenciales
        String credentials = productServiceUsername + ":" + productServicePassword;
        String base64Credentials = Base64.getEncoder()
            .encodeToString(credentials.getBytes(StandardCharsets.UTF_8));

        return builder
            .baseUrl("http://product-service/api/v1")
            .defaultHeader(HttpHeaders.AUTHORIZATION, 
                          "Basic " + base64Credentials)
            .defaultHeader(HttpHeaders.CONTENT_TYPE, 
                          MediaType.APPLICATION_JSON_VALUE)
            .build();
    }

    // Opción 2: Usar filtro personalizado
    @Bean
    public WebClient productWebClientWithFilter(WebClient.Builder builder) {
        return builder
            .baseUrl("http://product-service/api/v1")
            .filter(addAuthenticationHeader())
            .build();
    }

    private ExchangeFilterFunction addAuthenticationHeader() {
        return ExchangeFilterFunction.ofRequestProcessor(clientRequest -> {
            String credentials = productServiceUsername + ":" + 
                               productServicePassword;
            String base64 = Base64.getEncoder()
                .encodeToString(credentials.getBytes(StandardCharsets.UTF_8));

            ClientRequest authorizedRequest = ClientRequest.from(clientRequest)
                .header(HttpHeaders.AUTHORIZATION, "Basic " + base64)
                .build();

            return Mono.just(authorizedRequest);
        });
    }
}

